struct Permission {
    string name;
    string description;
    struct Permission* children;
};

struct Tree {
    Permission* root;
};

void managePermissions(Tree* tree, string operation, string details) {
    if (!tree || !tree->root) {
        cout << "Invalid tree structure." << endl;
        return;
    }

    Permission* node = tree->root;
    string* parts = new string[2];
    string* temp = new string[2];

    // Parse operation and details
    int i = 0;
    while (i < details.length() && details[i] != ' ') {
        temp[i] = details[i];
        i++;
    }
    temp[i] = ' ';
    i++;

    parts[0] = temp[0];
    parts[1] = temp[1];

    if (parts[0] == "add") {
        if (parts[1] == "permission") {
            // Add permission to the node
            Permission* newPerm = new Permission;
            newPerm->name = parts[1];
            newPerm->description = parts[2];
            newPerm->children = nullptr;

            if (node->children == nullptr) {
                node->children = newPerm;
            } else {
                // Traverse to the appropriate child
                Permission* current = node->children;
                while (current->children != nullptr) {
                    current = current->children;
                }
                current->children = newPerm;
            }
        } else {
            cout << "Invalid permission name." << endl;
        }
    } else if (parts[0] == "update") {
        if (parts[1] == "permission") {
            // Update permission
            Permission* newPerm = new Permission;
            newPerm->name = parts[1];
            newPerm->description = parts[2];
            newPerm->children = nullptr;

            // Find the node to update
            Permission* current = node;
            while (current != nullptr) {
                if (current->name == parts[1]) {
                    current->description = parts[2];
                    break;
                }
                current = current->children;
            }
            if (current == nullptr) {
                cout << "Permission not found." << endl;
            }
        } else {
            cout << "Invalid permission name." << endl;
        }
    } else if (parts[0] == "remove") {
        if (parts[1] == "permission") {
            // Remove permission
            Permission* current = node;
            while (current != nullptr) {
                if (current->name == parts[1]) {
                    // Remove from the tree
                    if (current->children != nullptr) {
                        Permission* temp = current->children;
                        current->children = nullptr;
                        delete temp;
                    }
                    break;
                }
                current = current->children;
            }
            if (current == nullptr) {
                cout << "Permission not found." << endl;
            }
        } else {
            cout << "Invalid permission name." << endl;
        }
    } else {
        cout << "Invalid operation." << endl;
    }

    delete[] temp;
    delete[] parts;
}

