fn process_grid_operations(matrix: &[Vec<u32>], operations: &[&str]) -> Vec<Vec<u32>> {
    let mut grid = matrix.to_vec();
    for &op in operations {
        match op {
            "rotate" => {
                // Rotate 90 degrees clockwise
                let mut rotated = Vec::new();
                for i in 0..grid.len() {
                    rotated.push(Vec::new());
                    for j in 0..grid[i].len() {
                        rotated[i].push(grid[grid.len() - 1 - j][j]);
                    }
                }
                grid = rotated;
            }
            "flip" => {
                // Flip horizontally
                let mut flipped = Vec::new();
                for i in 0..grid.len() {
                    let mut row = Vec::new();
                    for j in 0..grid[i].len() {
                        row.push(grid[i][grid[i].len() - 1 - j]);
                    }
                    flipped.push(row);
                }
                grid = flipped;
            }
            "invert" => {
                // Invert values (0 <-> 1)
                let mut inverted = Vec::new();
                for i in 0..grid.len() {
                    let mut row = Vec::new();
                    for j in 0..grid[i].len() {
                        row.push(1 - grid[i][j]);
                    }
                    inverted.push(row);
                }
                grid = inverted;
            }
            _ => {}
        }
    }
    grid
}
